mapper.select:
select member_id, user_id, level, level_name, discount_rate, total_spending, create_time, update_time
from t_member
where user_id = #{userId}

mapper.update:
update t_member
level = #{level}, level_name = #{levelName}, discount_rate = #{discountRate}, total_spending = #{totalSpending}, update_time = now(),
where user_id = #{userId}
